"use strict";(globalThis.webpackChunkmy_website=globalThis.webpackChunkmy_website||[]).push([[4690],{3987(e,t,o){o.r(t),o.d(t,{assets:()=>h,contentTitle:()=>n,default:()=>u,frontMatter:()=>r,metadata:()=>s,toc:()=>d});const s=JSON.parse('{"id":"stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-4","title":"Discourses \u2014 Book 1, Chapter 4","description":"Book 1 \u2014 Chapter 4","source":"@site/docs/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-4.md","sourceDirName":"stoicism/epictetus/discourses/book-1","slug":"/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-4","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-4","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":4,"frontMatter":{"sidebar_position":4,"title":"Discourses \u2014 Book 1, Chapter 4","sidebar_label":"Book 1, Ch. 4"},"sidebar":"philosophersSidebar","previous":{"title":"Book 1, Ch. 3","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-3"},"next":{"title":"Book 1, Ch. 5","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-5"}}');var a=o(4848),i=o(8453);const r={sidebar_position:4,title:"Discourses \u2014 Book 1, Chapter 4",sidebar_label:"Book 1, Ch. 4"},n="Discourses",h={},d=[{value:"Book 1 \u2014 Chapter 4",id:"book-1--chapter-4",level:2},{value:"On Progress, Or Moral Advance",id:"on-progress-or-moral-advance",level:3},{value:"Text",id:"text",level:2}];function l(e){const t={em:"em",h1:"h1",h2:"h2",h3:"h3",header:"header",p:"p",...(0,i.R)(),...e.components},{Details:o}=t;return o||function(e,t){throw new Error("Expected "+(t?"component":"object")+" `"+e+"` to be defined: you likely forgot to import, pass, or provide it.")}("Details",!0),(0,a.jsxs)(a.Fragment,{children:[(0,a.jsxs)("div",{style:{textAlign:"center"},children:[(0,a.jsx)(t.header,{children:(0,a.jsx)(t.h1,{id:"discourses",children:"Discourses"})}),(0,a.jsx)(t.h2,{id:"book-1--chapter-4",children:"Book 1 \u2014 Chapter 4"}),(0,a.jsx)(t.h3,{id:"on-progress-or-moral-advance",children:"On Progress, Or Moral Advance"})]}),"\n",(0,a.jsx)(t.p,{children:(0,a.jsx)(t.em,{children:"Translated by P.E. Matheson (Oxford: Clarendon Press, 1916)"})}),"\n",(0,a.jsxs)(o,{open:!0,children:[(0,a.jsx)("summary",{children:"Text"}),(0,a.jsx)(t.h2,{id:"text",children:"Text"}),(0,a.jsx)(t.p,{children:"How shall we describe 'progress'?  It is the state of him who having learnt from philosophers that man wills to get what is good, and wills to avoid what is evil, and having learnt also that peace and calm come to a man only if he fail not to get what he wills, and if he fall not into that which he avoids, has put away from him altogether the will to get anything and has postponed it to the future, and wills to avoid only such things as are dependent on his will. For if he tries to avoid anything beyond his will, he knows that, for all his avoidance, he will one day come to grief and be unhappy. And if this is the promise that virtue makes to us--the promise to produce happiness and peace and calm, surely progress toward virtue is progress toward each of these. For to whatever end the perfection of a thing leads, to that end is progress an approach."}),(0,a.jsx)(t.p,{children:"How is it then that, though we admit that this is the nature of virtue, we search elsewhere for progress and display it elsewhere?"}),(0,a.jsx)(t.p,{children:"What does virtue produce?"}),(0,a.jsx)(t.p,{children:"Peace of mind."}),(0,a.jsx)(t.p,{children:"Who then makes progress? Is it he who has read many treatises of Chrysippus? Can this be virtue--to have understood Chrysippus? For if this be so, we must admit that progress is nothing but to understand a lot of sayings of Chrysippus. But, the fact is, we admit that virtue tends to one result, and yet declare that progress, the approach to virtue, tends to another."}),(0,a.jsx)(t.p,{children:"'Yonder man', he says, 'can already read Chrysippus by himself.'"}),(0,a.jsx)(t.p,{children:"Bravo, by the gods, you make progress, fellow. Progress indeed! Why do you mock him? Why do you draw him away from the sense of his own shortcomings? Will you not show him what virtue really means, that he may learn where to seek for progress? Miserable man, there is only one place to seek it--where your work lies. Where does it lie? It lies in the region of will; that you may not fail to get what you will to get, nor fall into what you will to avoid; it lies in avoiding error in the region of impulse, impulse to act and impulse not to act: it lies in assent and the withholding of assent, that in these you may never be deceived.  But the first department I have named comes first and is most necessary. If you merely tremble and mourn and seek to escape misfortune, progress is of course impossible."}),(0,a.jsx)(t.p,{children:"Show me your progress then in this field. You act as though when I"}),(0,a.jsx)(t.p,{children:"was talking to an athlete and said, 'Show me your shoulders', he answered, 'Look at my leaping-weights.' That is for you and your leaping-weights to look to; I want to see the final result of your leaping-weights."}),(0,a.jsx)(t.p,{children:"'Take the treatise on \"Impulse\" and learn how I have read it.'"}),(0,a.jsx)(t.p,{children:"Slave, that is not what I am looking for--I want to know what impulses you have, for action and against it, to know what you will to get and will to avoid; how you plan and purpose and prepare--whether in harmony with nature, or out of harmony with nature. Show me that you act in harmony with nature, and I will tell you that you are making progress; act out of harmony with nature, and I bid you begone and write books on such things and not merely expound them. What good, I ask, will they do you? Do not you know that the whole book is worth but five pence? Do you think then that the man who expounds it is worth more? Therefore never seek your work in one place and progress in another."}),(0,a.jsx)(t.p,{children:"Where then is progress?"}),(0,a.jsx)(t.p,{children:"If any one of you, dismissing things without, has brought his mind to bear on his own will, to work out its full development, that he may bring it into perfect harmony with nature--lofty, free, unhindered, untrammelled, trustworthy, self-respecting; if he has learnt that he that wills to get or to avoid what is not in his power cannot be trustworthy nor free, but must needs himself change as they change, fitful as the winds, and must needs have made himself subservient to others, who can procure or hinder such things; and if, in a word, when he rises in the morning he guards and keeps these principles, washes as one that is trustworthy, eats as one that is self-respecting, and on each occasion that arises labours to achieve his main tasks, even as the runner makes running his one aim and the voice-trainer his training--he is the man who is indeed in the path of progress and who has not travelled to no purpose."}),(0,a.jsx)(t.p,{children:"But if all his efforts are turned to the study of books, if on this he spends his labour, and for this has gone abroad, then I bid him go straight home and not neglect what he finds there; for this that he has gone abroad for is nothing; his true work is to study to remove from his life mourning and lamentation, the 'ah me' and 'alas for my misery', the talk of 'bad fortune' and 'misfortune'; and to learn, what is death, what is exile, what is imprisonment, what is the cup of hemlock; that he may be able to say in prison, 'My dear Crito, if it pleases the gods, so be it', and not such words as 'miserable old man that I am, is it for this I kept my grey hairs?' (Plato, Crito, 43d) Whose words are they? Do you think I shall name to you a mean man of no reputation? Are they not the words of Priam and of Oedipus? Are they not the words of all kings that are? For what else are tragedies but a portrayal in such"}),(0,a.jsx)(t.p,{children:"metrical form of the sufferings of men who have set their admiration on outward things? If delusion after all were the only means for a man to learn this lesson--the lesson that not one of the things beyond the compass of our will concerns us, then I for my part would choose a delusion such as this, if it should procure me a life of undisturbed tranquillity; I leave it to you to see what you choose."}),(0,a.jsx)(t.p,{children:"What then does Chrysippus offer us?"}),(0,a.jsx)(t.p,{children:"'That you may know', he says, 'that these truths from which tranquillity and peace of mind come to men are not false--take my books and you shall find that what gives me peace of mind is true and in harmony with nature.'"}),(0,a.jsx)(t.p,{children:"O great good fortune! O great benefactor, who shows us the way! And yet--though all men have raised temples and altars to Triptolemus, for teaching us the cultivation of the crops, yet what man of you ever set up an altar in honour of him who found the truth and brought it to light and published it among all men--not the truth of mere living, but the truth that leads to right living? Who ever dedicated a shrine or an image for this gift, or worships God for it? I say shall we, who offer sacrifices because the gods gave us wheat or the vine, never give thanks to God that they produced this manner of fruit in the mind of men, whereby they were to show us the true way of happiness?"})]})]})}function u(e={}){const{wrapper:t}={...(0,i.R)(),...e.components};return t?(0,a.jsx)(t,{...e,children:(0,a.jsx)(l,{...e})}):l(e)}},8453(e,t,o){o.d(t,{R:()=>r,x:()=>n});var s=o(6540);const a={},i=s.createContext(a);function r(e){const t=s.useContext(i);return s.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function n(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:r(e.components),s.createElement(i.Provider,{value:t},e.children)}}}]);